dashboard.definition:
{
    "title": "Data Quality and TA Health",
    "description": "Input health, errors, and ingest volume.",
    "inputs": {
        "input_time": {
            "type": "input.timerange",
            "title": "Time Range",
            "options": { "token": "time", "defaultValue": "-24h@h,now" }
        }
    },
    "dataSources": {
        "ds_last_run": {
            "type": "ds.search",
            "name": "Last successful collection per input",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=cloud_llm_apis:health | stats latest(_time) as last_seen latest(status) as last_status sum(events) as events by input_name input_type | eval age_minutes=round((now()-last_seen)/60,1) | fieldformat last_seen=strftime(last_seen,\"%F %T\") | sort age_minutes",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_errors": {
            "type": "ds.search",
            "name": "Errors over time",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=cloud_llm_apis:health status=error | timechart span=1h count as errors by input_name",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_events_by_st": {
            "type": "ds.search",
            "name": "Events by sourcetype",
            "options": {
                "query": "index=cloud_llm_apis | timechart span=1h count by sourcetype",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_total_events": {
            "type": "ds.search",
            "name": "Total events ingested",
            "options": {
                "query": "index=cloud_llm_apis | stats count",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_error_rate": {
            "type": "ds.search",
            "name": "Collection error rate",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=cloud_llm_apis:health | stats count(eval(status=\"error\")) as errors count as runs | eval error_rate_pct=round(errors/runs*100,1) | fields error_rate_pct",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        }
    },
    "visualizations": {
        "viz_total_events": {
            "type": "splunk.singlevalue",
            "title": "Total Events Ingested",
            "dataSources": { "primary": "ds_total_events" },
            "options": { "majorField": "count" }
        },
        "viz_error_rate": {
            "type": "splunk.singlevalue",
            "title": "Collection Error Rate (%)",
            "dataSources": { "primary": "ds_error_rate" },
            "options": {
                "majorField": "error_rate_pct",
                "unit": "%",
                "majorColor": "> 0=#D41F1F"
            }
        },
        "viz_last_run": {
            "type": "splunk.table",
            "title": "Last Collection per Input (age in minutes)",
            "dataSources": { "primary": "ds_last_run" }
        },
        "viz_errors": {
            "type": "splunk.column",
            "title": "API/Collection Errors Over Time",
            "dataSources": { "primary": "ds_errors" },
            "options": { "xField": "_time", "stackMode": "stacked" }
        },
        "viz_events_by_st": {
            "type": "splunk.area",
            "title": "Events Ingested by Sourcetype",
            "dataSources": { "primary": "ds_events_by_st" },
            "options": { "xField": "_time", "stackMode": "stacked" }
        }
    },
    "layout": {
        "type": "grid",
        "globalInputs": [ "input_time" ],
        "structure": [
            { "item": "viz_total_events", "type": "block", "position": { "x": 0, "y": 0, "w": 600, "h": 180 } },
            { "item": "viz_error_rate", "type": "block", "position": { "x": 600, "y": 0, "w": 600, "h": 180 } },
            { "item": "viz_last_run", "type": "block", "position": { "x": 0, "y": 180, "w": 1200, "h": 280 } },
            { "item": "viz_errors", "type": "block", "position": { "x": 0, "y": 460, "w": 600, "h": 300 } },
            { "item": "viz_events_by_st", "type": "block", "position": { "x": 600, "y": 460, "w": 600, "h": 300 } }
        ]
    }
}
